      newMemberSources:topRows(c.sources,'newMembers',12).map(r=>compactRow(r,['SourceClean','newMembers','converted','retained','conversionRate','retentionRate','ltv','visitsPost'])),
      crmLeadSources:topRows(c.leadSources,'leads',12).map(r=>compactRow(r,['SourceGroup','leads','trials','won','trialRate','winRate','lost','open'])),
      newMemberTypes:topRows(c.newTypes,'trials',10).map(r=>compactRow(r,['NewType','trials','converted','retained','conversionRate','retentionRate','ltv'])),
      revenueCategories:topRows(c.categories,'revenue',12).map(r=>compactRow(r,['Category','revenue','items','buyers','share'])),
      products:topRows(c.products,'revenue',14).map(r=>compactRow(r,['Product','Category','revenue','items','buyers','atv'])),
      paidChurn:topRows(paidChurnRows(c),'churned',14).map(r=>compactRow(r,['MembershipClean','active','frozen','expiring','renewed','churned','churnRate','renewRate','avgSessionsPerMonth','avgUsage','avgAttendance','noShows'])),
      dayparts:topRows(c.dayparts,'revenue',8).map(r=>compactRow(r,['Daypart','classes','attendance','capacity','avg','fill','revenue','revPerClass'])),
      weekdays:topRows(c.weekdays,'revenue',8).map(r=>compactRow(r,['Day','classes','attendance','capacity','avg','fill','revenue','revPerClass'])),
