function lastPeriods(n=7){ const idx=APP.periods.findIndex(p=>p.key===state.period); return APP.periods.slice(Math.max(0,idx-n+1),idx+1).map(p=>p.key); }
function periodsFrom(startKey){
  const startIdx=APP.periods.findIndex(p=>p.key===startKey);
  const endIdx=APP.periods.findIndex(p=>p.key===state.period);
  if(startIdx===-1 || endIdx===-1 || endIdx<startIdx) return lastPeriods();
  return APP.periods.slice(startIdx,endIdx+1).map(p=>p.key);
}
function trendFmt(key){ return v=>key.includes('Rate')?pct(v):(key==='revenuePerVisit'||key.includes('Rev')||key==='revenuePerClass'||key==='newRevenue'||key==='renewedRevenue')?money(v):(key==='classAvg')?one(v):num(v); }
