function trendMembershipRows(period=selectedTrendPeriod()){
  const c=APP.data[period]?.[state.studio];
  if(!c) return [];
  const membershipRows=(c.churn||[])
    .filter(r=>Number(r.amount||0)>0)
    .map(r=>({name:r.MembershipClean,value:Number(r.amount||0),units:Number(r.expiring||0),kind:'membership'}));
  if(membershipRows.length) return membershipRows.sort((a,b)=>b.value-a.value).slice(0,8);
  return (c.products||[])
    .filter(r=>Number(r.revenue||0)>0)
    .map(r=>({name:r.Product,value:Number(r.revenue||0),units:Number(r.sales||0),kind:'product'}))
    .sort((a,b)=>b.value-a.value)
    .slice(0,8);
}
