function renderTrend(){
  const key=state.trendMetric;
  const psAsc=periodsFrom('2025-01');
  const valsAsc=psAsc.map(p=>metricValue(p,state.studio,key));
  // descending: most recent at top
  const ps=[...psAsc].reverse();
  const vals=[...valsAsc].reverse();
  const dataMax=Math.max(...vals,1);
  const w=900,rowGap=8,rowH=26,padL=148,padR=200,padTop=56,padBottom=22,h=Math.max(340,padTop+padBottom+(ps.length*rowH)+((ps.length-1)*rowGap));
  const plotW=w-padL-padR, plotH=h-padTop-padBottom;
  const fmt=trendFmt(key);
  const avg=vals.reduce((a,b)=>a+b,0)/Math.max(vals.length,1);
  const yMax=Math.max(dataMax*1.08, avg*1.05, 1);
  const toggle=$(`.trend-toggle[data-metric="${key}"]`);
  const label=toggle?.getAttribute('aria-label')||toggle?.dataset.tooltip||key;
  // latest = index 0 after reverse
  const latestVal=vals[0];
  const prevVal=vals[1]??vals[0];
  const changeValue=latestVal-prevVal;
  const changePct=prevVal?((changeValue/Math.abs(prevVal))*100).toFixed(1):null;
  const trendUp=changeValue>0, trendFlat=changeValue===0;
  const deltaLabel=trendFlat?'Flat vs last month':`${trendUp?'▲':'▼'} ${changePct?Math.abs(changePct)+'%':''} vs prior`;
  const trendColor=trendFlat?'var(--amber)':trendUp?'var(--green)':'var(--red)';
  const benchmarkX=padL + (avg/yMax)*plotW;
  const svgH = h;
  const bars=vals.map((v,i)=>{
    const y=padTop + i*(rowH+rowGap);
    const barW=Math.max((Math.max(v,0)/yMax)*plotW, 6);
    const isLatest=i===0;
    const labelText=periodLabel(ps[i]);
    const drill=`data-trend-period="${ps[i]}" tabindex="0" role="button" aria-label="Show ${periodLabel(ps[i])} item-level sales breakdown"`;
    const valueText=fmt(v);
    const valueWidth=Math.max(42, String(valueText).length*6.8);
    const valueInside=barW > Math.max(110, valueWidth + 34);
    const valueX=valueInside ? (padL + barW - 12) : (padL + barW + 10);
    return `
      <text class="trend-row-label${isLatest?' is-latest':''}" x="${padL-16}" y="${(y + rowH/2 + 4).toFixed(1)}" text-anchor="end">${labelText}</text>
      <rect class="trend-bar-modern${isLatest?' is-latest':''}" x="${padL}" y="${y.toFixed(1)}" width="${barW.toFixed(1)}" height="${rowH.toFixed(1)}" rx="10" ${drill}/>
      <text class="trend-bar-value${isLatest?' is-latest':''}${valueInside?' is-inside':''}" x="${valueX.toFixed(1)}" y="${(y + rowH/2 + 4).toFixed(1)}" text-anchor="${valueInside?'end':'start'}">${valueText}</text>`;
  }).join('');
  $('#trendChart').innerHTML=`<svg class="trend-svg-v2" viewBox="0 0 ${w-padR} ${svgH}" role="img" aria-label="Studio health trend chart" data-metric="${key}">
  <defs>
    <linearGradient id="trendBarFill" x1="0" y1="0" x2="1" y2="0">
      <stop offset="0%" stop-color="#6366f1"/>
      <stop offset="100%" stop-color="#8b5cf6"/>
    </linearGradient>
    <linearGradient id="trendBarFillActive" x1="0" y1="0" x2="1" y2="0">
      <stop offset="0%" stop-color="#f59e0b"/>
      <stop offset="100%" stop-color="#ef4444"/>
    </linearGradient>
  </defs>
  <line class="trend-benchmark-line" x1="${benchmarkX.toFixed(1)}" x2="${benchmarkX.toFixed(1)}" y1="${padTop}" y2="${(padTop+plotH).toFixed(1)}"/>
  <text class="trend-benchmark-label" x="${benchmarkX.toFixed(1)}" y="${(padTop-8).toFixed(1)}" text-anchor="middle">avg</text>
  ${bars}
</svg>`;
}
