    sessions:{label:'Sessions',key:'classes',fmt:num,summary:'Total scheduled sessions by unique class',action:'Adjust class mix to balance capacity'},
    visits:{label:'Visits',key:'attendance',fmt:num,summary:'Check-ins (visits) by unique class',action:'Identify classes driving attendance'},
