function metricDisplay(key,v){ if(['salesRev','sessionRev','revenuePerClass','revenuePerAttendee','auv','atv','newLtv'].includes(key)) return money(v); if(['fillRate','conversionRate','retentionRate','leadWinRate','leadYield','churnRate','avgSessionsUsedPct','avgAttendanceRate'].includes(key)) return pct(ratioMetricValue(key,v)); if(['classAvg','purchaseFrequency','avgSessionsPerMonth'].includes(key)) return one(v); return num(v); }
