function growthTextCell(key, good){ const ch=metricChange(key,1); if(!ch) return '<span class="mom-text neutral">n/a</span>'; const g=ch.delta; const cls=Math.abs(g)<0.0005?'neutral':((g>0&&good==='up')||(g<0&&good==='down')?'good':'bad'); return `<span class="mom-text ${cls}">${ch.label}</span>`; }
function growthDirection(key){ const g=current().growth?.[key]; if(g===null||g===undefined) return 'No prior'; if(Math.abs(g)<0.0005) return 'Flat'; return g>0?'Up':'Down'; }
function growthRead(key, good){ const g=current().growth?.[key]; if(g===null||g===undefined) return 'No comparison'; if(Math.abs(g)<0.0005) return 'Stable'; const favorable=(g>0&&good==='up')||(g<0&&good==='down'); return favorable?'Positive movement':'Needs attention'; }
