function churnRiskBand(r){ const risk=Number(r.churnRate||0), exp=Number(r.expiring||0), use=Number(r.avgSessionsPerMonth||0); if(risk>=0.25 || exp>=40 && risk>=0.18) return 'High'; if(risk>=0.15 || use<2) return 'Medium'; return 'Watch'; }
function churnAction(r){ const risk=Number(r.churnRate||0), use=Number(r.avgSessionsPerMonth||0), renew=Number(r.renewRate||0); if(risk>=0.2 && use<2) return 'Call low-usage expiries'; if(risk>=0.2) return 'Renewal save offer'; if(renew>=0.75) return 'Protect renewal script'; if(use<2) return 'Usage reactivation'; return 'Monitor next cycle'; }
