function diagRow(key,good){
  const currVal=metricValue(state.period,state.studio,key);
  const prev2=lastPeriods(2); const hasPrev=prev2.length>=2;
  const prevVal=hasPrev?metricValue(prev2[1],state.studio,key):null;
  const bench=diagBenchmark(key);
  let targetLabel='Prior month', gap='—', priority='Watch', action='Monitor vs prior month';
  if(bench){
    const diff=bench.flip?(bench.target-currVal):(currVal-bench.target);
    const onTrack=bench.flip?currVal<=bench.target:currVal>=bench.target;
    const magnitude=Math.abs(bench.isRate?diff:(diff/Math.max(bench.target,0.01)));
    targetLabel=bench.label;
    gap=bench.isRate?`${diff>=0?'+':''}${Math.round(diff*100)}pp`:`${diff>=0?'+':''}${(diff/Math.max(bench.target,0.01)*100).toFixed(0)}%`;
    if(onTrack){ priority=magnitude>0.15?'Exceeds':'On Track'; action='Sustain and protect'; }
    else{ priority=magnitude>0.15?'High':magnitude>0.05?'Medium':'Watch'; action=priority==='High'?'Needs immediate focus':priority==='Medium'?'Build improvement plan':'Monitor closely'; }
  } else if(hasPrev&&prevVal!=null&&prevVal!==0){
    const chg=(currVal-prevVal)/Math.max(Math.abs(prevVal),1);
    const isPositiveGood=good==='up';
    const gapDir=isPositiveGood?chg>=0:chg<=0;
    const mag=Math.abs(chg);
    gap=`${chg>=0?'+':''}${Math.round(chg*100)}%`;
    if(gapDir){ priority=mag>0.10?'Strong':'On Track'; action='Sustain momentum'; }
    else{ priority=mag>0.15?'High':mag>0.05?'Medium':'Watch'; action=priority==='High'?'Needs immediate focus':priority==='Medium'?'Review drivers':'Monitor vs prior month'; }
  }
  return {targetLabel, gap, priority, action};
}
