function nestedFormatTable(c){
  const rowTones=['gold','blue','sage','plum','red','cyan'];
  const headers=['Format / class','Cls','Pax','Avg','Fill','Late / Empty','Revenue','New / Conv'];
  if(!c.formats.length) return table(headers, []);
  const rows=c.formats.map((r,i)=>{
    const tone=rowTones[i%rowTones.length];
    const children=c.classes.filter(x=>x.Format===r.name).sort((a,b)=>Number(b.revenue||0)-Number(a.revenue||0));
    const parentDrill={
      title:`${r.name} format`,
      summary:`${r.name} generated ${money(r.revenue)} across ${num(r.classes)} sessions, with ${pct(r.fill)} fill and ${num(r.converted)} conversions.`,
      headers:['Metric','Value'],
      rows:[['Classes',num(r.classes)],['Attendance',num(r.attendance)],['Capacity',num(r.capacity)],['Class average',one(r.avg)],['Fill',pct(r.fill)],['Empty classes',num(r.empty)],['Late cancellations',num(r.lateCancels)],['Revenue',money(r.revenue)],['Revenue / class',money(r.revPerClass)],['New visits',num(r.newMembers)],['Conversions',num(r.converted)],['Conversion rate',pct(r.conversionRate)]],
      formula:'Format rows aggregate class sessions, attendance, capacity, late cancellations, revenue and first-visit outcomes by class format.',
      source:{kind:'sessionFormat',value:r.name}
    };
    const childRows=children.map(cls=>{
      const outcome=classOutcome(cls);
      const childDrill={
        title:cls.Class,
        summary:`${cls.Class} contributed ${money(cls.revenue)} from ${num(cls.classes)} sessions at ${pct(cls.fill)} fill${outcome ? `, with ${num(outcome.newMembers)} new visits and ${num(outcome.converted)} conversions.` : '.'}`,
        headers:['Metric','Value'],
        rows:[['Format',cls.Format],['Sessions',num(cls.classes)],['Attendance',num(cls.attendance)],['Capacity',num(cls.capacity)],['Booked',num(cls.booked)],['Class average',one(cls.avg)],['Fill',pct(cls.fill)],['Late cancellations',num(cls.late)],['Empty classes',num(cls.empty)],['Revenue',money(cls.revenue)],['Revenue / class',money(cls.revPerClass)],['New visits',outcome?num(outcome.newMembers):'-'],['Conversions',outcome?num(outcome.converted):'-']],
        formula:'Class rows are grouped beneath their parent format. New / Conv uses the new-member export by selected month, studio and first-visit class name with Conversion Status exactly equal to Converted.',
        source:{kind:'sessionClass',value:cls.Class}
      };
      const childRow={cells:[`<span class="nested-class-name"><b>${esc(trunc(cls.Class,42))}</b><small>${esc(cls.Format)}</small></span>`,num(cls.classes),num(cls.attendance),one(cls.avg),barPct(cls.fill),`${num(cls.late)} / ${num(cls.empty)}`,money(cls.revenue),outcomeText(outcome)],drill:childDrill};
      return `<tr>${tableCells(headers,[childRow],childRow)}</tr>`;
    }).join('');
    const nested=children.length?`<div class="nested-inner-wrap"><table class="nested-data-table"><thead><tr>${headers.map(h=>`<th>${h}</th>`).join('')}</tr></thead><tbody>${childRows}</tbody></table></div>`:`<div class="nested-inner-wrap"><div class="empty">No class-level records for this format.</div></div>`;
    const parentRow={cells:[fmtPill(r.name),num(r.classes),num(r.attendance),one(r.avg),barPct(r.fill),`${num(r.lateCancels)} / ${num(r.empty)}`,money(r.revenue),`${num(r.newMembers)} / ${num(r.converted)}`],drill:parentDrill};
    return `<tr class="format-parent row-tone-${tone}">${tableCells(headers,[parentRow],parentRow)}</tr><tr class="nested-row row-tone-${tone}"><td class="nested-cell" colspan="${headers.length}">${nested}</td></tr>`;
  }).join('');
  const totals=c.formats.reduce((a,r)=>({classes:a.classes+Number(r.classes||0),attendance:a.attendance+Number(r.attendance||0),capacity:a.capacity+Number(r.capacity||0),late:a.late+Number(r.lateCancels||0),empty:a.empty+Number(r.empty||0),revenue:a.revenue+Number(r.revenue||0),newMembers:a.newMembers+Number(r.newMembers||0),converted:a.converted+Number(r.converted||0)}),{classes:0,attendance:0,capacity:0,late:0,empty:0,revenue:0,newMembers:0,converted:0});
  const avg=totals.attendance/Math.max(totals.classes,1), fill=totals.attendance/Math.max(totals.capacity,1);
  const foot=`<tfoot><tr><td>Total</td><td>${num(totals.classes)}</td><td>${num(totals.attendance)}</td><td>${one(avg)}</td><td>${pct(fill)}</td><td>${num(totals.late)} / ${num(totals.empty)}</td><td>${money(totals.revenue)}</td><td>${num(totals.newMembers)} / ${num(totals.converted)}</td></tr></tfoot>`;
  return `<table class="data-table nested-format-table"><thead><tr>${headers.map(h=>`<th>${h}</th>`).join('')}</tr></thead><tbody>${rows}</tbody>${foot}</table>`;
}
function plainText(v){ return String(v ?? '').replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').trim(); }
function parseDisplayNumber(v){
  const s=plainText(v);
  if(!s || s==='-' || /\/|#|n\/a/i.test(s)) return null;
  const cleaned=s.replace(/\s+/g,'').replace(/,/g,'');
  const moneyMatch=cleaned.match(/^₹(-?\d+(?:\.\d+)?)(Cr|L|K)?$/i);
  const pctMatch=cleaned.match(/^(-?\d+(?:\.\d+)?)%$/);
  const multMatch=cleaned.match(/^(-?\d+(?:\.\d+)?)x$/i);
  const numMatch=cleaned.match(/^-?\d+(?:\.\d+)?$/);
  let n, type='num';
  if(moneyMatch){ n=Number(moneyMatch[1]); type='money'; if(/Cr/i.test(moneyMatch[2]||'')) n*=10000000; else if(/L/i.test(moneyMatch[2]||'')) n*=100000; else if(/K/i.test(moneyMatch[2]||'')) n*=1000; }
  else if(pctMatch){ n=Number(pctMatch[1]); type='pct'; }
  else if(multMatch){ n=Number(multMatch[1]); type='mult'; }
  else if(numMatch){ n=Number(cleaned); }
  else return null;
  return Number.isFinite(n) ? {value:n,type} : null;
}
function totalRows(headers, rows, options={}){
  if(!rows.length) return '';
  if(Array.isArray(options.footerCells)){
    return `<tfoot><tr>${options.footerCells.map((v,i)=>`<td>${i===0?esc(v):htmlCell(v)}</td>`).join('')}</tr></tfoot>`;
  }
  const body=rows.map(r=>r.cells||[]);
  const cells=headers.map((h,i)=>{
    if(i===0) return 'Total';
    const vals=body.map(r=>parseDisplayNumber(r[i])).filter(Boolean);
    if(!vals.length) return '-';
    const type=vals[0].type;
    if(!vals.every(v=>v.type===type)) return '-';
    const sum=vals.reduce((a,b)=>a+b.value,0);
    if(type==='money') return money(sum);
    if(type==='pct') return pct(sum/vals.length/100);
    if(type==='mult') return `${one(sum/vals.length)}x`;
    return num(sum);
  });
  return `<tfoot><tr>${cells.map((v,i)=>`<td>${i===0?esc(v):htmlCell(v)}</td>`).join('')}</tr></tfoot>`;
}
